                      <p className="text-xs text-gray-400 font-bold">
                        {lang === 'bn' ? 'অভিভাবকদের পাঠানো ভর্তি আবেদন পর্যালোচনা এবং অনুমোদন করুন' : 'Review and approve/reject online registration forms filed by guardians'}
                      </p>
