                                                className="w-full py-1.5 border border-dashed border-gray-250 hover:border-[#005c53] hover:text-[#005c53] text-gray-400 bg-white rounded-lg flex items-center justify-center gap-1 text-[10px] font-bold cursor-pointer transition-colors"
