              // DATABASE AND BACKEND EXPORT CODE TEXTS
              const postgresSchemaCode = `-- 1. Students Table with Core Demographics
CREATE TABLE students (
    student_id VARCHAR(50) PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    class VARCHAR(20) NOT NULL,
    section VARCHAR(10) NOT NULL,
    roll INTEGER NOT NULL,
    gender VARCHAR(10) NOT NULL,
    blood_group VARCHAR(10),
    guardian_name VARCHAR(100) NOT NULL,
    guardian_contact VARCHAR(20) NOT NULL,
    status VARCHAR(20) DEFAULT 'Active' CHECK (status IN ('Active', 'Inactive')),
    admission_date DATE DEFAULT CURRENT_DATE
);

-- Indexing for rapid queries
CREATE INDEX idx_students_search ON students(class, section, status);

-- 2. Monthly Attendance Matrix Table
CREATE TABLE attendance (
    attendance_id SERIAL PRIMARY KEY,
    student_id VARCHAR(50) REFERENCES students(student_id) ON DELETE CASCADE,
    month_index INTEGER NOT NULL CHECK (month_index BETWEEN 0 AND 11),
    year INTEGER NOT NULL,
    -- JSONB schema representing days: { "1": "P", "2": "A", "3": "F", ... }
    daily_logs JSONB NOT NULL DEFAULT '{}'::jsonb,
    total_present INTEGER DEFAULT 0,
    total_absent INTEGER DEFAULT 0,
    attendance_percentage NUMERIC(5, 2) DEFAULT 0.00,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE (student_id, month_index, year)
);

-- PL/pgSQL database trigger to auto-calculate totals and percentages in real-time
CREATE OR REPLACE FUNCTION calculate_attendance_totals()
RETURNS TRIGGER AS $$
DECLARE
    entry RECORD;
    p_count INTEGER := 0;
    a_count INTEGER := 0;
    total_days INTEGER := 0;
BEGIN
    FOR entry IN SELECT * FROM jsonb_each_text(NEW.daily_logs) LOOP
        IF entry.value = 'P' THEN
            p_count := p_count + 1;
        ELSIF entry.value = 'A' THEN
            a_count := a_count + 1;
        END IF;
    END LOOP;
    
    NEW.total_present := p_count;
    NEW.total_absent := a_count;
    total_days := p_count + a_count;
    
    IF total_days > 0 THEN
        NEW.attendance_percentage := ROUND((p_count::NUMERIC / total_days::NUMERIC) * 100.0, 2);
    ELSE
        NEW.attendance_percentage := 0.00;
    END IF;
    
    NEW.updated_at := CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_recalculate_attendance
BEFORE INSERT OR UPDATE ON attendance
FOR EACH ROW
EXECUTE FUNCTION calculate_attendance_totals();`;

              const pythonOpenpyxlCode = `import openpyxl
from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
from openpyxl.utils import get_column_letter

def generate_attendance_excel(month_name, class_name, section, student_records):
    """
    Generates a beautifully styled A4 Landscape Excel workbook for monthly attendance.
    Supports auto-formulas for Total Present, Total Absent, and Attendance %.
    """
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = f"Attendance_{month_name}"
    
    # Enable grid lines
    ws.views.sheetView[0].showGridLines = True
    
    # Theme configuration
    teal_fill = PatternFill(start_color="005C53", end_color="005C53", fill_type="solid")
    light_teal_fill = PatternFill(start_color="E6F2F0", end_color="E6F2F0", fill_type="solid")
    friday_fill = PatternFill(start_color="FFF2CC", end_color="FFF2CC", fill_type="solid")
    present_fill = PatternFill(start_color="E2F0D9", end_color="E2F0D9", fill_type="solid")
    absent_fill = PatternFill(start_color="FCE4D6", end_color="FCE4D6", fill_type="solid")
    
    white_bold = Font(name="Calibri", size=11, bold=True, color="FFFFFF")
    charcoal_bold = Font(name="Calibri", size=11, bold=True, color="1F2937")
    regular_font = Font(name="Calibri", size=10, color="000000")
    
    thin_border = Border(
        left=Side(style='thin', color='CCCCCC'),
        right=Side(style='thin', color='CCCCCC'),
        top=Side(style='thin', color='CCCCCC'),
        bottom=Side(style='thin', color='CCCCCC')
    )
    
    # Title Block Header
    ws.merge_cells("A1:AJ1")
    ws["A1"] = "STUDENTS CARE MODEL SCHOOL - MONTHLY ATTENDANCE REGISTER"
    ws["A1"].font = Font(name="Calibri", size=16, bold=True, color="005C53")
    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")
    ws.row_dimensions[1].height = 32
    
    ws.merge_cells("A2:AJ2")
    ws["A2"] = f"Month: {month_name} 2026 | Class: {class_name} | Section: {section}"
    ws["A2"].font = Font(name="Calibri", size=11, italic=True, color="4B5563")
    ws["A2"].alignment = Alignment(horizontal="center", vertical="center")
    ws.row_dimensions[2].height = 20
    
    # Roster Grid Headers
    headers = ["SL", "Student ID", "Roll", "Student Name"] + [str(d) for d in range(1, 32)] + ["Present", "Absent", "Percentage %"]
    ws.append([]) # spacer
    ws.row_dimensions[4].height = 26
    
    for col_idx, h in enumerate(headers, 1):
        cell = ws.cell(row=4, column=col_idx, value=h)
        cell.fill = teal_fill
        cell.font = white_bold
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = thin_border
        
    # Appending records
    for idx, student in enumerate(student_records, 5):
        ws.row_dimensions[idx].height = 20
        ws.cell(row=idx, column=1, value=idx-4).font = charcoal_bold
        ws.cell(row=idx, column=2, value=student["id"]).font = regular_font
        ws.cell(row=idx, column=3, value=student["roll"]).font = regular_font
        ws.cell(row=idx, column=4, value=student["name"]).font = Font(name="Calibri", size=10, bold=True)
        
        for col_i in [1, 2, 3]:
            ws.cell(row=idx, column=col_i).alignment = Alignment(horizontal="center", vertical="center")
            ws.cell(row=idx, column=col_i).border = thin_border
        ws.cell(row=idx, column=4).border = thin_border
        
        # Populate daily logs (1 to 31)
        for day in range(1, 32):
            col_pos = day + 4
            status_val = student.get("logs", {}).get(day, "")
            cell = ws.cell(row=idx, column=col_pos, value=status_val)
            cell.font = regular_font
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.border = thin_border
            
            if status_val == "F":
                cell.fill = friday_fill
            elif status_val == "P":
                cell.fill = present_fill
            elif status_val == "A":
                cell.fill = absent_fill
                
        # Excel Formulas for calculations in Columns AJ, AK, AL (Cols 36, 37, 38)
        row = idx
        ws.cell(row=row, column=36, value=f'=COUNTIF(E{row}:AI{row}, "P")').font = charcoal_bold
        ws.cell(row=row, column=36).alignment = Alignment(horizontal="center", vertical="center")
        ws.cell(row=row, column=36).border = thin_border
        ws.cell(row=row, column=36).fill = light_teal_fill
        
        ws.cell(row=row, column=37, value=f'=COUNTIF(E{row}:AI{row}, "A")').font = charcoal_bold
        ws.cell(row=row, column=37).alignment = Alignment(horizontal="center", vertical="center")
        ws.cell(row=row, column=37).border = thin_border
        ws.cell(row=row, column=37).fill = light_teal_fill
        
        ws.cell(row=row, column=38, value=f'=IF((AJ{row}+AK{row})>0, AJ{row}/(AJ{row}+AK{row}), 0)').font = charcoal_bold
        ws.cell(row=row, column=38).alignment = Alignment(horizontal="center", vertical="center")
        ws.cell(row=row, column=38).border = thin_border
        ws.cell(row=row, column=38).number_format = '0.0%'
        ws.cell(row=row, column=38).fill = light_teal_fill

    # Resize columns
    ws.column_dimensions['A'].width = 5
    ws.column_dimensions['B'].width = 13
    ws.column_dimensions['C'].width = 7
    ws.column_dimensions['D'].width = 24
    for c in range(5, 36):
        ws.column_dimensions[get_column_letter(c)].width = 4
    ws.column_dimensions[get_column_letter(36)].width = 9
    ws.column_dimensions[get_column_letter(37)].width = 9
    ws.column_dimensions[get_column_letter(38)].width = 12
    
    wb.save(f"SCMS_Roster_{class_name}_{section}.xlsx")`;

